#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return (*y) - (*x);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B;
        scanf("%d %d", &A, &B);
        int *c = (int *)malloc(A * B * sizeof(int));
        int *d = (int *)malloc(A * B * sizeof(int));
        for (int i = 0; i < A * B; i++) {
            scanf("%d", &c[i]);
        }
        for (int i = 0; i < A * B; i++) {
            scanf("%d", &d[i]);
        }
        int *max_votes = (int *)malloc(A * B * sizeof(int));
        for (int i = 0; i < A * B; i++) {
            max_votes[i] = (c[i] > d[i]) ? c[i] : d[i];
        }
        qsort(max_votes, A * B, sizeof(int), compare);
        int count = 0;
        for (int i = 0; i < A * B; i += B) {
            int max = 0;
            for (int j = 0; j < B; j++) {
                if (c[i + j] > max) {
                    max = c[i + j];
                }
            }
            if (max == max_votes[i / B]) {
                count++;
            }
        }
        printf("%d\n", count);
        free(c);
        free(d);
        free(max_votes);
    }
    return 0;
}

