import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int A = sc.nextInt();
            int B = sc.nextInt();
            int[] c = new int[A * B];
            int[] d = new int[A * B];
            for (int i = 0; i < A * B; i++) {
                c[i] = sc.nextInt();
            }
            for (int i = 0; i < A * B; i++) {
                d[i] = sc.nextInt();
            }
            int[] max_votes = new int[A * B];
            for (int i = 0; i < A * B; i++) {
                max_votes[i] = Math.max(c[i], d[i]);
            }
            Arrays.sort(max_votes);
            int count = 0;
            for (int i = 0; i < A * B; i += B) {
                int max = 0;
                for (int j = 0; j < B; j++) {
                    if (c[i + j] > max) {
                        max = c[i + j];
                    }
                }
                if (max == max_votes[A * B - 1 - i / B]) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

